import React from 'react';
import { Box, Icon, Text } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface IconTextRowProps extends SDUIComponentProps {
  icon: string;
  iconColor?: string;
  iconSize?: string;
  text: string;
  textType?: string;
  textColor?: string;
  mb?: string;
}

export default function IconTextRowAdapter({
  props,
}: {
  props: IconTextRowProps;
  context: SDUIContext;
}) {
  const {
    icon,
    iconColor = 'BRAND_BASE_01',
    iconSize = 'sm',
    text,
    textType = 'bodyMD',
    textColor,
    mb,
  } = props;

  return (
    <Box direction align="center" mb={mb}>
      <Icon name={String(icon)} size={iconSize} color={iconColor} mr="nano" />
      <Box flex={1}>
        <Text type={textType} color={textColor}>
          {text}
        </Text>
      </Box>
    </Box>
  );
}

