import React from 'react';
import { Text, Icon } from '@semparar/design-system-app';
import type {
  SDUIComponentProps,
  SDUIContext,
  SDUIRichTextChild,
} from '../models';

interface RichTextProps extends SDUIComponentProps {
  children: SDUIRichTextChild[];
  mt?: string;
  mb?: string;
  align?: string;
}

function renderNode(node: SDUIRichTextChild, index: number) {
  switch (node.type) {
    case 'text': {
      const style: Record<string, string> = {};
      if (node.bold) style.fontWeight = 'bold';
      if (node.italic) style.fontStyle = 'italic';
      return (
        <Text
          key={index}
          type="bodyMD"
          color={node.color}
          style={Object.keys(style).length > 0 ? style : undefined}
        >
          {node.value}
        </Text>
      );
    }
    case 'link':
      return (
        <Text
          key={index}
          type="bodyMD"
          color="PRYMARY_BASE_02"
          underline
          onPress={() => {}}
        >
          {node.text}
        </Text>
      );
    case 'icon':
      return (
        <Icon
          key={index}
          name={node.name}
          color={node.color}
          size={node.size ? String(node.size) : 'sm'}
        />
      );
    case 'br':
      return <Text key={index}>{'\n'}</Text>;
    default:
      return null;
  }
}

export default function RichTextAdapter({
  props,
}: {
  props: RichTextProps;
  context: SDUIContext;
}) {
  const { children, mt, mb, align } = props;

  if (!Array.isArray(children) || children.length === 0) {
    return null;
  }

  return (
    <Text type="bodyMD" mt={mt} mb={mb} align={align}>
      {children.map(renderNode)}
    </Text>
  );
}

