import React from 'react';
import { ScrollView } from 'react-native';
import { Text, Box, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';

registerAllAdapters();

const richTextScreen: SDUIScreen = {
  id: 'rich_text_demo',
  context: {
    product: { name: 'Abastecimento' },
  },
  body: [
    {
      type: 'heading',
      props: { text: 'Rich Text Examples' },
    },
    {
      type: 'section_heading',
      props: { text: 'Bold & Italic' },
    },
    {
      type: 'rich_text',
      props: {
        children: [
          { type: 'text', value: 'Este texto é ' },
          { type: 'text', value: 'negrito', bold: true },
          { type: 'text', value: ' e este é ' },
          { type: 'text', value: 'itálico', italic: true },
          { type: 'text', value: '.' },
        ],
        mb: 'xs',
      },
    },
    {
      type: 'separator',
      props: {},
    },
    {
      type: 'section_heading',
      props: { text: 'Inline Links' },
    },
    {
      type: 'rich_text',
      props: {
        children: [
          { type: 'text', value: 'Confira os ' },
          { type: 'text', value: 'termos', bold: true },
          { type: 'text', value: ' ou ' },
          { type: 'link', text: 'fale conosco', to: 'app://suporte' },
          { type: 'text', value: ' para mais informações.' },
        ],
        mb: 'xs',
      },
    },
    {
      type: 'separator',
      props: {},
    },
    {
      type: 'section_heading',
      props: { text: 'Icons Inline' },
    },
    {
      type: 'rich_text',
      props: {
        children: [
          { type: 'icon', name: 'icon-check-circle', color: 'BRAND_BASE_01' },
          { type: 'text', value: ' Voucher criado com sucesso' },
        ],
        mb: 'xs',
      },
    },
    {
      type: 'separator',
      props: {},
    },
    {
      type: 'section_heading',
      props: { text: 'Line Breaks' },
    },
    {
      type: 'rich_text',
      props: {
        children: [
          { type: 'text', value: 'Linha 1: Pontos utilizados' },
          { type: 'br' },
          { type: 'text', value: 'Linha 2: Valor em reais' },
          { type: 'br' },
          { type: 'text', value: 'Linha 3: ' },
          { type: 'text', value: 'Data de expiração', bold: true },
        ],
        mb: 'xs',
      },
    },
    {
      type: 'separator',
      props: {},
    },
    {
      type: 'section_heading',
      props: { text: 'Colored Text' },
    },
    {
      type: 'rich_text',
      props: {
        children: [
          { type: 'text', value: 'Status: ' },
          { type: 'text', value: 'Disponível', bold: true, color: 'BRAND_BASE_01' },
          { type: 'text', value: ' | ' },
          { type: 'text', value: 'Expirado', bold: true, color: 'SUPPORT_BASE_01' },
        ],
        mb: 'xs',
      },
    },
    {
      type: 'separator',
      props: {},
    },
    {
      type: 'section_heading',
      props: { text: 'Mixed (RFC Example)' },
    },
    {
      type: 'rich_text',
      props: {
        children: [
          { type: 'text', value: 'Confira os ' },
          { type: 'text', value: 'termos', bold: true },
          { type: 'text', value: ' ou ' },
          { type: 'link', text: 'fale conosco', to: 'app://suporte' },
        ],
      },
    },
  ],
};

function RichTextDemo() {
  return (
    <ScrollView style={{ flex: 1 }}>
      <Box p="xxxs">
        <Text type="headingMDL" mb="nano">
          SDUI Rich Text Adapter
        </Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="xs">
          Renders inline formatted text with bold, italic, links, icons, and
          line breaks — all from a JSON children array (RFC section 3.3).
        </Text>
        <SeparatorHorizontal mv="xs" />
        <ScreenRenderer screen={richTextScreen} />
      </Box>
    </ScrollView>
  );
}

const meta: Meta = {
  title: 'SDUI/RichText',
  component: RichTextDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

