import React from 'react';
import { Box, CardVehicleTags } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface VoucherCardProps extends SDUIComponentProps {
  icon: string;
  vehicleName: string;
  title: string;
  titleDescription: string;
  date: string;
  dateNumber: string;
  statusTitle: string;
  status: string;
  typeTag?: string;
  ghostButtonText?: string;
}

const TAG_TYPE_MAP: Record<string, string> = {
  success: 'success',
  error: 'error',
  alert: 'alert',
  highlight: 'highlight',
};

export default function VoucherCardAdapter({
  props,
}: {
  props: VoucherCardProps;
  context: SDUIContext;
}) {
  const {
    icon,
    vehicleName,
    title,
    titleDescription,
    date,
    dateNumber,
    statusTitle,
    status,
    typeTag = 'highlight',
    ghostButtonText = 'Exibir detalhes',
  } = props;

  return (
    <Box ml="middle" mr="middle" mt="smaller">
      <CardVehicleTags
        vehicleName={vehicleName}
        icon={icon as any}
        title={title}
        titleDescription={titleDescription}
        date={date}
        dateNumber={dateNumber}
        statusTitle={statusTitle}
        status={status}
        ghostButtonText={ghostButtonText}
        onGhostButtonPress={() => {}}
        type="extended"
        typeTag={(TAG_TYPE_MAP[typeTag] ?? typeTag) as any}
        version="2.0"
      />
    </Box>
  );
}

