import { registerToDefault } from '../registry';
import type { SDUIComponentRenderer } from '../models';

import HeadingAdapter from './HeadingAdapter';
import TextAdapter from './TextAdapter';
import BalanceDisplayAdapter from './BalanceDisplayAdapter';
import PointsInputAdapter from './PointsInputAdapter';
import ButtonAdapter from './ButtonAdapter';
import LinkAdapter from './LinkAdapter';
import AlertAdapter from './AlertAdapter';
import ListTextIconAdapter from './ListTextIconAdapter';
import SeparatorAdapter from './SeparatorAdapter';
import IconTextRowAdapter from './IconTextRowAdapter';
import SectionHeadingAdapter from './SectionHeadingAdapter';
import RichTextAdapter from './RichTextAdapter';

// FIXME: use something like "props: DUIProps<Foo, Bar>" during component
//  creation in order to avoid eliminate the use of "as SDUIComponentRenderer"
const adapters: Record<string, SDUIComponentRenderer> = {
  heading: HeadingAdapter as SDUIComponentRenderer,
  text: TextAdapter as SDUIComponentRenderer,
  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
  points_input: PointsInputAdapter as SDUIComponentRenderer,
  button: ButtonAdapter as SDUIComponentRenderer,
  link: LinkAdapter as SDUIComponentRenderer,
  alert: AlertAdapter as SDUIComponentRenderer,
  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
  separator: SeparatorAdapter as SDUIComponentRenderer,
  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
  rich_text: RichTextAdapter as SDUIComponentRenderer,
};

export function registerAllAdapters(): void {
  Object.entries(adapters).forEach(([type, renderer]) => {
    registerToDefault(type, renderer);
  });
}

export { adapters };

import type { ComponentType } from 'react';

// ---------------------------------------------------------------------------
// SDUI — Server Driven UI Type System
// RFC: .claude/rfc-conteudo-dinamico.txt
// ---------------------------------------------------------------------------

// ---- 3.4  Context & Interpolation ----------------------------------------

export type SDUIContextValue =
  | string
  | number
  | boolean
  | null
  | SDUIContext
  | SDUIContextValue[];

export interface SDUIContext {
  [key: string]: SDUIContextValue;
}

// ---- 3.5  JSON Logic (subset) --------------------------------------------

/**
 * Accesses a value from the context using dot notation.
 * @example { var: 'balance.pointsFormatted' }
 */
export interface SDUIVarOperator {
  var: string;
}

export type SDUILogicPrimitive = string | number | boolean | null;
export type SDUILogicOperand = SDUIVarOperator | SDUILogicPrimitive | SDUIRule;

export interface SDUIComparisonRule {
  '=='?: [SDUILogicOperand, SDUILogicOperand];
  '!='?: [SDUILogicOperand, SDUILogicOperand];
  '>'?: [SDUILogicOperand, SDUILogicOperand];
  '<'?: [SDUILogicOperand, SDUILogicOperand];
  '>='?: [SDUILogicOperand, SDUILogicOperand];
  '<='?: [SDUILogicOperand, SDUILogicOperand];
}

export interface SDUILogicalRule {
  and?: SDUIRule[];
  or?: SDUIRule[];
  '!'?: SDUIRule;
}

export type SDUIRule = SDUIComparisonRule | SDUILogicalRule;

/**
 * A boolean value computed from a JSON Logic rule.
 * Used for visibility, enabled state, or any boolean prop.
 * @example { rule: { '>': [{ var: 'form.points' }, 0] } }
 */
export interface SDUIConditional {
  rule: SDUIRule;
}

export interface SDUIValidationRule {
  rule: SDUIRule;
  message: string;
}

export interface SDUIValidation {
  rules: SDUIValidationRule[];
}

// ---- 3.3  Rich Text -------------------------------------------------------

export interface SDUITextNode {
  type: 'text';
  value: string;
  bold?: boolean;
  italic?: boolean;
  color?: string;
}

export interface SDUILinkNode {
  type: 'link';
  text: string;
  to: string;
  trackEvent?: string;
}

export interface SDUIIconNode {
  type: 'icon';
  name: string;
  color?: string;
  size?: number;
}

export interface SDUILineBreakNode {
  type: 'br';
}

export type SDUIRichTextChild =
  | SDUITextNode
  | SDUILinkNode
  | SDUIIconNode
  | SDUILineBreakNode;

export interface SDUIRichText {
  type: 'rich_text';
  children: SDUIRichTextChild[];
}

// ---- 3.2  Components ------------------------------------------------------

export type SDUIPropValue =
  | string
  | number
  | boolean
  | null
  | SDUIConditional
  | SDUIValidation
  | SDUIRichText
  | SDUIPropValue[]
  | { [key: string]: SDUIPropValue };

export interface SDUIComponentProps {
  [key: string]: SDUIPropValue;
}

export interface SDUIComponent<T extends string = string> {
  type: T;
  props: SDUIComponentProps;
  visible?: SDUIConditional;
}

// ---- 3.1  Screen Structure ------------------------------------------------

export type SDUIHeader = SDUIComponent;
export type SDUIFooter = SDUIComponent;

export interface SDUIScreen {
  id: string;
  context: SDUIContext;
  header?: SDUIHeader;
  body: SDUIComponent[];
  footer?: SDUIFooter;
}

export interface SDUIScreenResponse {
  screen: SDUIScreen;
}

// ---- Component Registry ---------------------------------------------------

export type SDUIComponentRenderer<P extends SDUIComponentProps = SDUIComponentProps> =
  ComponentType<{
    props: P;
    context: SDUIContext;
  }>;

export interface SDUIComponentRegistry {
  [type: string]: SDUIComponentRenderer;
}

// ---- Known Component Types (voucher screens) ------------------------------

export const SDUI_KNOWN_TYPES = [
  'heading',
  'text',
  'balance_display',
  'points_input',
  'button',
  'link',
  'alert',
  'list_text_icon',
  'separator',
  'icon_text_row',
  'section_heading',
  'nav_header',
  'rich_text',
] as const;

export type SDUIKnownType = (typeof SDUI_KNOWN_TYPES)[number];

