import React, { useState } from 'react';
import { ScrollView } from 'react-native';
import { Text, Box, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen, SDUIComponent } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';

registerAllAdapters();

const VOUCHER_CARDS: SDUIComponent[] = [
  {
    type: 'voucher_card',
    props: {
      icon: 'icon-gas-station',
      vehicleName: 'Voucher para abastecimento',
      title: 'Valor em pontos',
      titleDescription: '2.500',
      date: 'Data do resgate',
      dateNumber: '20/02/2026',
      statusTitle: 'Status do pedido',
      status: 'Finalizado',
      typeTag: 'success',
    },
  },
  {
    type: 'voucher_card',
    props: {
      icon: 'icon-parking',
      vehicleName: 'Voucher para estacionamento',
      title: 'Valor em pontos',
      titleDescription: '7.500',
      date: 'Data do resgate',
      dateNumber: '18/02/2026',
      statusTitle: 'Status do pedido',
      status: 'Enviado',
      typeTag: 'success',
    },
  },
  {
    type: 'voucher_card',
    props: {
      icon: 'icon-invoice',
      vehicleName: 'Cashback na fatura',
      title: 'Valor em pontos',
      titleDescription: '5.000',
      date: 'Data do resgate',
      dateNumber: '15/02/2026',
      statusTitle: 'Status do pedido',
      status: 'Pendente',
      typeTag: 'highlight',
    },
  },
  {
    type: 'voucher_card',
    props: {
      icon: 'icon-document',
      vehicleName: 'Desconto em multas e débitos',
      title: 'Valor em pontos',
      titleDescription: '3.000',
      date: 'Data do resgate',
      dateNumber: '12/02/2026',
      statusTitle: 'Status do pedido',
      status: 'Estornado',
      typeTag: 'error',
    },
  },
  {
    type: 'voucher_card',
    props: {
      icon: 'icon-gas-station',
      vehicleName: 'Voucher para abastecimento',
      title: 'Valor em pontos',
      titleDescription: '1.500',
      date: 'Data do resgate',
      dateNumber: '10/02/2026',
      statusTitle: 'Status do pedido',
      status: 'Cancelado',
      typeTag: 'alert',
    },
  },
  {
    type: 'voucher_card',
    props: {
      icon: 'icon-parking',
      vehicleName: 'Voucher para estacionamento',
      title: 'Valor em pontos',
      titleDescription: '10.000',
      date: 'Data do resgate',
      dateNumber: '08/02/2026',
      statusTitle: 'Status do pedido',
      status: 'Confirmado',
      typeTag: 'highlight',
    },
  },
];

function buildListScreen(): SDUIScreen {
  return {
    id: 'voucher_list',
    context: {},
    header: {
      type: 'nav_header',
      props: { title: 'Meus pedidos', showBack: true },
    },
    body: VOUCHER_CARDS,
  };
}

function buildEmptyScreen(): SDUIScreen {
  return {
    id: 'voucher_list_empty',
    context: {},
    header: {
      type: 'nav_header',
      props: { title: 'Meus pedidos', showBack: true },
    },
    body: [
      {
        type: 'empty_state',
        props: {
          icon: 'icon-shopping-cart',
          title: 'Nenhum pedido feito',
          description:
            'Quando você usar seus pontos em pedidos, eles aparecerão aqui.',
        },
      },
    ],
  };
}

function buildFilteredEmptyScreen(): SDUIScreen {
  return {
    id: 'voucher_list_filtered',
    context: {},
    header: {
      type: 'nav_header',
      props: { title: 'Meus pedidos', showBack: true },
    },
    body: [
      {
        type: 'empty_state',
        props: {
          icon: 'icon-search',
          title: 'Não há resultados para sua busca',
        },
      },
    ],
  };
}

type ViewState = 'list' | 'empty' | 'filtered';

function VoucherListSDUI() {
  const [view, setView] = useState<ViewState>('list');

  const screens: Record<ViewState, SDUIScreen> = {
    list: buildListScreen(),
    empty: buildEmptyScreen(),
    filtered: buildFilteredEmptyScreen(),
  };

  return (
    <ScrollView style={{ flex: 1 }}>
      <Box p="xxxs">
        <Text type="headingMDL" mb="nano">
          SDUI: Meus Vouchers
        </Text>
        <Text type="bodySM" color="INTENSE_COLOR_03" mb="xs">
          Renders the voucher list screen entirely from JSON via the SDUI engine.
          All 6 voucher cards with different statuses + empty states.
        </Text>

        <Box direction mb="xs" style={{ gap: 8 }}>
          {(['list', 'empty', 'filtered'] as const).map(v => (
            <Text
              key={v}
              type="bodySM"
              color={view === v ? 'BRIGHT_COLOR_01' : 'DEEP_COLOR_01'}
              onPress={() => setView(v)}
              style={{
                backgroundColor: view === v ? '#0066FF' : '#E0E0E0',
                borderRadius: 8,
                paddingHorizontal: 12,
                paddingVertical: 6,
                overflow: 'hidden',
              }}
            >
              {v === 'list' ? 'List (6)' : v === 'empty' ? 'Empty' : 'Filtered'}
            </Text>
          ))}
        </Box>

        <SeparatorHorizontal mv="xs" />
        <ScreenRenderer screen={screens[view]} />
      </Box>
    </ScrollView>
  );
}

const meta: Meta = {
  title: 'SDUI/VoucherList',
  component: VoucherListSDUI,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

